    public List<BatchAcceptedEventResponse> getBatchAcceptedEvents(
            TransactionReceipt transactionReceipt) {
        List<Contract.EventValuesWithLog> valueList = extractEventParametersWithLog(BATCHACCEPTED_EVENT, transactionReceipt);
        ArrayList<BatchAcceptedEventResponse> responses = new ArrayList<BatchAcceptedEventResponse>(valueList.size());
        for (Contract.EventValuesWithLog eventValues : valueList) {
            BatchAcceptedEventResponse typedResponse = new BatchAcceptedEventResponse();
            typedResponse.log = eventValues.getLog();
            typedResponse.operator = (String) eventValues.getIndexedValues().get(0).getValue();
            typedResponse.count = (BigInteger) eventValues.getNonIndexedValues().get(0).getValue();
            typedResponse.timestamp = (BigInteger) eventValues.getNonIndexedValues().get(1).getValue();
            responses.add(typedResponse);
        }
        return responses;
    }

    public void subscribeBatchAcceptedEvent(BigInteger fromBlock, BigInteger toBlock,
            List<String> otherTopics, EventSubCallback callback) {
        String topic0 = eventEncoder.encode(BATCHACCEPTED_EVENT);
        subscribeEvent(topic0,otherTopics,fromBlock,toBlock,callback);
    }

    public void subscribeBatchAcceptedEvent(EventSubCallback callback) {
        String topic0 = eventEncoder.encode(BATCHACCEPTED_EVENT);
        subscribeEvent(topic0,callback);
    }

